fun solve(s: String): Array<String> {
    val segments = mutableListOf<String>()
    val seen = mutableSetOf<String>()
    var currentSegment = ""
    var startIndex = 0

    while (startIndex < s.length) {
        currentSegment = ""
        var found = false
        for (i in startIndex until s.length) {
            currentSegment += s[i]
            if (!seen.contains(currentSegment)) {
                segments.add(currentSegment)
                seen.add(currentSegment)
                startIndex = i + 1
                found = true
                break
            }
        }
        if (!found) {
            currentSegment = s.substring(startIndex)
            segments.add(currentSegment)
            seen.add(currentSegment)
            break
        }
    }

    return segments.toTypedArray()
}
